#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        printf("YES\n");
        int total = N * N;
        for (int i = 0; i < total; ++i) {
            if (i) printf(" ");
            printf(i % 2 == 0 ? "1" : "-1");
        }
        printf("\n");
    }
    return 0;
}

